<template>\n  <div class=\"markdown-body\" v-html=\"rendered\"></div>\n</template>\n\n<script setup lang=\"ts\">\nimport { computed } from 'vue'\n\nconst props = defineProps<{ content: string }>()\n\nconst rendered = computed(() => {\n  let html = props.content || ''\n  // 代码块\n  html = html.replace(/```(\\w*)\\n([\\s\\S]*?)```/g, '<pre><code class=\"language-$1\">$2</code></pre>')\n  // 标题\n  html = html.replace(/^#### (.*$)/gm, '<h4>$1</h4>')\n  html = html.replace(/^### (.*$)/gm, '<h3>$1</h3>')\n  html = html.replace(/^## (.*$)/gm, '<h2>$1</h2>')\n  html = html.replace(/^# (.*$)/gm, '<h1>$1</h1>')\n  // 粗体/斜体\n  html = html.replace(/\\*\\*(.*?)\\*\\*/g, '<strong>$1</strong>')\n  html = html.replace(/\\*(.*?)\\*/g, '<em>$1</em>')\n  // 行内代码\n  html = html.replace(/`(.*?)`/g, '<code>$1</code>')\n  // 链接\n  html = html.replace(/\\[([^\\]]+)\\]\\(([^)]+)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>')\n  // 图片\n  html = html.replace(/!\\[([^\\]]*)\\]\\(([^)]+)\\)/g, '<img src=\"$2\" alt=\"$1\" />')\n  // 无序列表\n  html = html.replace(/^\\- (.*$)/gm, '<li>$1</li>')\n  // 分隔线\n  html = html.replace(/^---$/gm, '<hr />')\n  // 换行\n  html = html.replace(/\\n\\n/g, '</p><p>')\n  html = html.replace(/\\n/g, '<br>')\n  html = '<p>' + html + '</p>'\n  return html\n})\n</script>\n\n<style scoped>\n.markdown-body { line-height: 1.8; font-size: 16px; color: #333; }\n.markdown-body :deep(h1) { font-size: 24px; margin: 24px 0 12px; border-bottom: 1px solid #eee; padding-bottom: 8px; }\n.markdown-body :deep(h2) { font-size: 20px; margin: 20px 0 10px; }\n.markdown-body :deep(h3) { font-size: 18px; margin: 16px 0 8px; }\n.markdown-body :deep(code) { background: #f5f5f5; padding: 2px 6px; border-radius: 3px; font-size: 14px; }\n.markdown-body :deep(pre) { background: #282c34; color: #abb2bf; padding: 16px; border-radius: 6px; overflow-x: auto; }\n.markdown-body :deep(pre code) { background: none; padding: 0; color: inherit; }\n.markdown-body :deep(a) { color: #007bff; }\n.markdown-body :deep(img) { max-width: 100%; border-radius: 4px; }\n.markdown-body :deep(hr) { border: none; border-top: 1px solid #eee; margin: 20px 0; }\n.markdown-body :deep(li) { margin-left: 20px; }\n</style>